{"code":"prs = github.list_pull_requests(state="open")
total_count = len(prs)

# Group by repository manually
repo_counts = {}
for p in prs:
    repo = p["repo"]
    repo_counts[repo] = repo_counts.get(repo, 0) + 1

# Find max
most_repo = max(repo_counts.items(), key=lambda x: x[1])

(total_count, most_repo[0], most_repo[1])"}
